1	package unstable
2	
3	import (
4		"context"
5		"fmt"
6		"net/http"
7	
8		"github.com/go-git/go-git/v6/plumbing"
9	
10		"entire.io/entire/git-sync"
11		"entire.io/entire/git-sync/internal/internalbridge"
12		"entire.io/entire/git-sync/internal/syncer"
13		"entire.io/entire/git-sync/internal/validation"
14	)
15	
16	const DefaultMaterializedMaxObjects = syncer.DefaultMaterializedMaxObjects
17	
18	type (
19		Result      = syncer.Result
20		ProbeResult = syncer.ProbeResult
21		FetchResult = syncer.FetchResult
22		RefInfo     = syncer.RefInfo
23		Stats       = syncer.Stats
24		Measurement = syncer.Measurement
25	)
26	
27	type Options struct {
28		HTTPClient *http.Client
29		Auth       gitsync.AuthProvider
30	}
31	
32	type Client struct {
33		httpClient *http.Client
34		auth       gitsync.AuthProvider
35	}
36	
37	type AdvancedOptions struct {
38		CollectStats           bool   `json:"collectStats"`
39		MeasureMemory          bool   `json:"measureMemory"`
40		Verbose                bool   `json:"verbose"`
41		Progress               bool   `json:"progress"`
42		MaxPackBytes           int64  `json:"maxPackBytes"`
43		TargetMaxPackBytes     int64  `json:"targetMaxPackBytes"`
44		TargetMaxRefUpdates    int    `json:"targetMaxRefUpdates"`
45		MaterializedMaxObjects int    `json:"materializedMaxObjects"`
46		BootstrapStrategy      string `json:"bootstrapStrategy,omitempty"`
47	}
48	
49	// BootstrapStrategy values accepted by AdvancedOptions.BootstrapStrategy.
50	// Empty is treated as the default (first-parent).
51	//
52	// BootstrapStrategyTopo additionally requires the target to allow
53	// non-fast-forward updates under the refs/gitsync/ namespace, since
54	// successive checkpoints under topological ordering aren't guaranteed
55	// to be in an ancestor-descendant relationship and the internal temp
56	// ref may receive non-ff updates between batches. Major hosts allow
57	// this by default; only locked-down deployments need to be checked.
58	const (
59		BootstrapStrategyFirstParent = "first-parent"
60		BootstrapStrategyTopo        = "topo"
61	)
62	
63	// Validate rejects unknown values up front so callers don't have to
64	// wait for the deep bootstrap planning path to surface them. It runs
65	// on every request method regardless of whether the value will end
66	// up being consulted, since silently accepting a typo on a
67	// non-bootstrap path is worse than failing fast.
68	func (o AdvancedOptions) Validate() error {
69		switch o.BootstrapStrategy {
70		case "", BootstrapStrategyFirstParent, BootstrapStrategyTopo:
71			return nil
72		default:
73			return fmt.Errorf("unsupported bootstrap strategy %q (want %q or %q)",
74				o.BootstrapStrategy, BootstrapStrategyFirstParent, BootstrapStrategyTopo)
75		}
76	}
77	
78	type ProbeRequest struct {
79		Source             gitsync.Endpoint
80		Target             *gitsync.Endpoint
81		IncludeTags        bool
82		AllRefs            bool
83		ExcludeRefPrefixes []string
84		Protocol           gitsync.ProtocolMode
85		Options            AdvancedOptions
86	}
87	
88	type SyncRequest struct {
89		Source  gitsync.Endpoint
90		Target  gitsync.Endpoint
91		Scope   gitsync.RefScope
92		Policy  gitsync.SyncPolicy
93		DryRun  bool
94		Options AdvancedOptions
95	}
96	
97	type BootstrapRequest struct {
98		Source      gitsync.Endpoint
99		Target      gitsync.Endpoint
100		Scope       gitsync.RefScope
101		IncludeTags bool
102		BestEffort  bool
103		Protocol    gitsync.ProtocolMode
104		Options     AdvancedOptions
105	}
106	
107	type FetchRequest struct {
108		Source      gitsync.Endpoint
109		Scope       gitsync.RefScope
110		IncludeTags bool
111		Protocol    gitsync.ProtocolMode
112		HaveRefs    []string
113		HaveHashes  []plumbing.Hash
114		Options     AdvancedOptions
115	}
116	
117	func New(opts Options) *Client {
118		return &Client{httpClient: opts.HTTPClient, auth: opts.Auth}
119	}
120	
121	func (c *Client) Probe(ctx context.Context, req ProbeRequest) (ProbeResult, error) {
122		if err := req.Options.Validate(); err != nil {
123			return ProbeResult{}, fmt.Errorf("probe: %w", err)
124		}
125		cfg, err := c.buildProbeConfig(ctx, req)
126		if err != nil {
127			return ProbeResult{}, err
128		}
129		result, err := syncer.Probe(ctx, cfg)
130		if err != nil {
131			return ProbeResult{}, fmt.Errorf("probe: %w", err)
132		}
133		return result, nil
134	}
135	
136	func (c *Client) Plan(ctx context.Context, req SyncRequest) (Result, error) {
137		if err := req.Options.Validate(); err != nil {
138			return Result{}, fmt.Errorf("plan: %w", err)
139		}
140		if err := req.Policy.Validate(); err != nil {
141			return Result{}, fmt.Errorf("plan: %w", err)
142		}
143		planReq := req
144		planReq.DryRun = true
145		cfg, err := c.buildSyncConfig(ctx, planReq)
146		if err != nil {
147			return Result{}, err
148		}
149		result, err := syncer.Run(ctx, cfg)
150		if err != nil {
151			return Result{}, fmt.Errorf("plan: %w", err)
152		}
153		return result, nil
154	}
155	
156	func (c *Client) Sync(ctx context.Context, req SyncRequest) (Result, error) {
157		if err := req.Options.Validate(); err != nil {
158			return Result{}, fmt.Errorf("sync: %w", err)
159		}
160		if err := req.Policy.Validate(); err != nil {
161			return Result{}, fmt.Errorf("sync: %w", err)
162		}
163		cfg, err := c.buildSyncConfig(ctx, req)
164		if err != nil {
165			return Result{}, err
166		}
167		result, err := syncer.Run(ctx, cfg)
168		if err != nil {
169			return Result{}, fmt.Errorf("sync: %w", err)
170		}
171		return result, nil
172	}
173	
174	func (c *Client) Replicate(ctx context.Context, req SyncRequest) (Result, error) {
175		if err := req.Options.Validate(); err != nil {
176			return Result{}, fmt.Errorf("replicate: %w", err)
177		}
178		req.Policy.Mode = gitsync.ModeReplicate
179		if err := req.Policy.Validate(); err != nil {
180			return Result{}, fmt.Errorf("replicate: %w", err)
181		}
182		cfg, err := c.buildSyncConfig(ctx, req)
183		if err != nil {
184			return Result{}, err
185		}
186		result, err := syncer.Run(ctx, cfg)
187		if err != nil {
188			return Result{}, fmt.Errorf("replicate: %w", err)
189		}
190		return result, nil
191	}
192	
193	func (c *Client) Bootstrap(ctx context.Context, req BootstrapRequest) (Result, error) {
194		if err := req.Options.Validate(); err != nil {
195			return Result{}, fmt.Errorf("bootstrap: %w", err)
196		}
197		cfg, err := c.buildBootstrapConfig(ctx, req)
198		if err != nil {
199			return Result{}, err
200		}
201		result, err := syncer.Bootstrap(ctx, cfg)
202		if err != nil {
203			return Result{}, fmt.Errorf("bootstrap: %w", err)
204		}
205		return result, nil
206	}
207	
208	func (c *Client) Fetch(ctx context.Context, req FetchRequest) (FetchResult, error) {
209		if err := req.Options.Validate(); err != nil {
210			return FetchResult{}, fmt.Errorf("fetch: %w", err)
211		}
212		cfg, err := c.buildFetchConfig(ctx, req)
213		if err != nil {
214			return FetchResult{}, err
215		}
216		result, err := syncer.Fetch(ctx, cfg, append([]string(nil), req.HaveRefs...), append([]plumbing.Hash(nil), req.HaveHashes...))
217		if err != nil {
218			return FetchResult{}, fmt.Errorf("fetch: %w", err)
219		}
220		return result, nil
221	}
222	
223	func (c *Client) buildProbeConfig(ctx context.Context, req ProbeRequest) (syncer.Config, error) {
224		source, err := c.resolveEndpoint(ctx, req.Source, gitsync.SourceRole)
225		if err != nil {
226			return syncer.Config{}, err
227		}
228		cfg := syncer.Config{
